36: /**
37:  * Base class for HTTP/1.1 request and response encoders.
38:  */
39: class StreamEncoderImpl : public virtual StreamEncoder,
40:                           public Stream,
41:                           public Logger::Loggable<Logger::Id::http>,
42:                           public StreamCallbackHelper,
43:                           public Http1StreamEncoderOptions {
44: public:
45:   ~StreamEncoderImpl() override {
46:     // When the stream goes away, undo any read blocks to resume reading.
47:     while (read_disable_calls_ != 0) {
48:       StreamEncoderImpl::readDisable(false);
49:     }
50:   }
51:   // Http::StreamEncoder
52:   void encodeData(Buffer::Instance& data, bool end_stream) override;
53:   void encodeMetadata(const MetadataMapVector&) override;
54:   Stream& getStream() override { return *this; }
55:   Http1StreamEncoderOptionsOptRef http1StreamEncoderOptions() override { return *this; }
56: 
57:   // Http::Http1StreamEncoderOptions
58:   void disableChunkEncoding() override { disable_chunk_encoding_ = true; }
59: 
60:   // Http::Stream
61:   void addCallbacks(StreamCallbacks& callbacks) override { addCallbacksHelper(callbacks); }
62:   void removeCallbacks(StreamCallbacks& callbacks) override { removeCallbacksHelper(callbacks); }
63:   CodecEventCallbacks* registerCodecEventCallbacks(CodecEventCallbacks* codec_callbacks) override;
64:   // After this is called, for the HTTP/1 codec, the connection should be closed, i.e. no further
65:   // progress may be made with the codec.
66:   void resetStream(StreamResetReason reason) override;
67:   void readDisable(bool disable) override;
68:   uint32_t bufferLimit() const override;
69:   absl::string_view responseDetails() override { return details_; }
70:   const Network::ConnectionInfoProvider& connectionInfoProvider() override;
71:   void setFlushTimeout(std::chrono::milliseconds) override {
72:     // HTTP/1 has one stream per connection, thus any data encoded is immediately written to the
73:     // connection, invoking any watermarks as necessary. There is no internal buffering that would
74:     // require a flush timeout not already covered by other timeouts.
75:   }
76: 
77:   Buffer::BufferMemoryAccountSharedPtr account() const override { return buffer_memory_account_; }
78: 
79:   void setAccount(Buffer::BufferMemoryAccountSharedPtr account) override {
80:     // TODO(kbaichoo): implement account tracking for H1. Particularly, binding
81:     // the account to the buffers used. The current wiring is minimal, and used
82:     // to ensure the memory_account gets notified that the downstream request is
83:     // closing.
84:     buffer_memory_account_ = account;
85:   }
86: 
87:   void setIsResponseToHeadRequest(bool value) { is_response_to_head_request_ = value; }
88:   void setIsResponseToConnectRequest(bool value) { is_response_to_connect_request_ = value; }
89:   void setDetails(absl::string_view details) { details_ = details; }
90: 
91:   const StreamInfo::BytesMeterSharedPtr& bytesMeter() override { return bytes_meter_; }
92: 
93:   // http1 doesn't have a codec level stream id.
94:   absl::optional<uint32_t> codecStreamId() const override { return absl::nullopt; }
95: 
96: protected:
97:   StreamEncoderImpl(ConnectionImpl& connection, StreamInfo::BytesMeterSharedPtr&& bytes_meter);
98:   void encodeHeadersBase(const RequestOrResponseHeaderMap& headers, absl::optional<uint64_t> status,
99:                          bool end_stream, bool bodiless_request);
100:   void encodeTrailersBase(const HeaderMap& headers);
101: 
102:   Buffer::BufferMemoryAccountSharedPtr buffer_memory_account_;
103:   ConnectionImpl& connection_;
104:   uint32_t read_disable_calls_{};
105:   bool disable_chunk_encoding_ : 1;
106:   bool chunk_encoding_ : 1;
107:   bool connect_request_ : 1;
108:   bool is_tcp_tunneling_ : 1;
109:   bool is_response_to_head_request_ : 1;
110:   bool is_response_to_connect_request_ : 1;
111: 
112: private:
113:   /**
114:    * Called to encode an individual header.
115:    * @param key supplies the header to encode as a string_view.
116:    * @param value supplies the value to encode as a string_view.
117:    */
118:   void encodeHeader(absl::string_view key, absl::string_view value);
119: 
120:   /**
121:    * Called to finalize a stream encode.
122:    */
123:   void endEncode();
124: 
125:   /**
126:    * Encapsulates notification to various objects that the encode completed.
127:    */
128:   void notifyEncodeComplete();
129: 
130:   void encodeFormattedHeader(absl::string_view key, absl::string_view value,
131:                              HeaderKeyFormatterOptConstRef formatter);
132: 
133:   void flushOutput(bool end_encode = false);
134: 
135:   absl::string_view details_;
136:   StreamInfo::BytesMeterSharedPtr bytes_meter_;
137:   CodecEventCallbacks* codec_callbacks_{nullptr};
138: };
