140: /**
141:  * HTTP/1.1 response encoder.
142:  */
143: class ResponseEncoderImpl : public StreamEncoderImpl, public ResponseEncoder {
144: public:
145:   ResponseEncoderImpl(ConnectionImpl& connection, StreamInfo::BytesMeterSharedPtr&& bytes_meter,
146:                       bool stream_error_on_invalid_http_message)
147:       : StreamEncoderImpl(connection, std::move(bytes_meter)),
148:         stream_error_on_invalid_http_message_(stream_error_on_invalid_http_message) {}
149: 
150:   ~ResponseEncoderImpl() override {
151:     // Only the downstream stream should clear the downstream of the
152:     // memory account.
153:     //
154:     // There are cases where a corresponding upstream stream dtor might
155:     // be called, but the downstream stream isn't going to terminate soon
156:     // such as StreamDecoderFilterCallbacks::recreateStream().
157:     if (buffer_memory_account_) {
158:       buffer_memory_account_->clearDownstream();
159:     }
160:   }
161: 
162:   bool startedResponse() { return started_response_; }
163: 
164:   // Http::ResponseEncoder
165:   void encode1xxHeaders(const ResponseHeaderMap& headers) override;
166:   void encodeHeaders(const ResponseHeaderMap& headers, bool end_stream) override;
167:   void encodeTrailers(const ResponseTrailerMap& trailers) override { encodeTrailersBase(trailers); }
168: 
169:   bool streamErrorOnInvalidHttpMessage() const override {
170:     return stream_error_on_invalid_http_message_;
171:   }
172:   void setDeferredLoggingHeadersAndTrailers(Http::RequestHeaderMapConstSharedPtr,
173:                                             Http::ResponseHeaderMapConstSharedPtr,
174:                                             Http::ResponseTrailerMapConstSharedPtr,
175:                                             StreamInfo::StreamInfo&) override {}
176: 
177:   // For H/1, ResponseEncoder doesn't hold a pointer to RequestDecoder.
178:   // TODO(paulsohn): Enable H/1 codec to get a pointer to the new
179:   // request decoder on recreateStream, here or elsewhere.
180:   void setRequestDecoder(Http::RequestDecoder& /*decoder*/) override {}
181: 
182:   // Http1::StreamEncoderImpl
183:   void resetStream(StreamResetReason reason) override;
184: 
185: private:
186:   bool started_response_{};
187:   const bool stream_error_on_invalid_http_message_;
188: };
