894:         error_code_ = Http::Code::BadRequest;
895:         RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().BodyDisallowed));
896:         return codecProtocolError("http/1.1 protocol error: unsupported content length");
897:       }
898:     }
899:     ENVOY_CONN_LOG(trace, "codec entering upgrade mode for CONNECT request.", connection_);
900:     handling_upgrade_ = true;
901:   }
902: 
903:   // https://tools.ietf.org/html/rfc7230#section-3.3.3
904:   // If a message is received with both a Transfer-Encoding and a
905:   // Content-Length header field, the Transfer-Encoding overrides the
906:   // Content-Length. Such a message might indicate an attempt to
907:   // perform request smuggling (Section 9.5) or response splitting
908:   // (Section 9.4) and ought to be handled as an error. A sender MUST
909:   // remove the received Content-Length field prior to forwarding such
910:   // a message.
911: 
912: #ifndef ENVOY_ENABLE_UHV
913:   // This check is moved into default header validator.
914:   // TODO(yanavlasov): use runtime override here when UHV is moved into the main build
915: 
916:   // Reject message with Http::Code::BadRequest if both Transfer-Encoding and Content-Length
917:   // headers are present or if allowed by http1 codec settings and 'Transfer-Encoding'
918:   // is chunked - remove Content-Length and serve request.
919:   if (parser_->hasTransferEncoding() != 0 && request_or_response_headers.ContentLength()) {
920:     if (parser_->isChunked() && codec_settings_.allow_chunked_length_) {
921:       request_or_response_headers.removeContentLength();
922:     } else {
923:       error_code_ = Http::Code::BadRequest;
924:       RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().ChunkedContentLength));
925:       return codecProtocolError(
926:           "http/1.1 protocol error: both 'Content-Length' and 'Transfer-Encoding' are set.");
927:     }
928:   }
929: 
930:   // Per https://tools.ietf.org/html/rfc7230#section-3.3.1 Envoy should reject
931:   // transfer-codings it does not understand.
932:   // Per https://tools.ietf.org/html/rfc7231#section-4.3.6 a payload with a
933:   // CONNECT request has no defined semantics, and may be rejected.
934:   if (request_or_response_headers.TransferEncoding()) {
935:     const absl::string_view encoding = request_or_response_headers.getTransferEncodingValue();
936:     if (!absl::EqualsIgnoreCase(encoding, header_values.TransferEncodingValues.Chunked) ||
937:         parser_->methodName() == header_values.MethodValues.Connect) {
938:       error_code_ = Http::Code::NotImplemented;
939:       RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().InvalidTransferEncoding));
940:       return codecProtocolError("http/1.1 protocol error: unsupported transfer encoding");
