945:   auto statusor = onHeadersCompleteBase();
946:   if (!statusor.ok()) {
947:     RETURN_IF_ERROR(statusor.status());
948:   }
949: 
950:   header_parsing_state_ = HeaderParsingState::Done;
951: 
952:   // Returning CallbackResult::NoBodyData informs http_parser to not expect a body or further data
953:   // on this connection.
