1115: Status ServerConnectionImpl::handlePath(RequestHeaderMap& headers, absl::string_view method) {
1116:   const Http::HeaderValues& header_values = Http::Headers::get();
1117:   HeaderString path(header_values.Path);
1118: 
1119:   bool is_connect = (method == header_values.MethodValues.Connect);
1120: 
1121:   // The url is relative or a wildcard when the method is OPTIONS. Nothing to do here.
1122:   if (!is_connect && !active_request_->request_url_.getStringView().empty() &&
1123:       (active_request_->request_url_.getStringView()[0] == '/' ||
1124:        (method == header_values.MethodValues.Options &&
1125:         active_request_->request_url_.getStringView()[0] == '*'))) {
1126:     headers.addViaMove(std::move(path), std::move(active_request_->request_url_));
1127:     return okStatus();
1128:   }
1129: 
1130:   // If absolute_urls and/or connect are not going be handled, copy the url and return.
1131:   // This forces the behavior to be backwards compatible with the old codec behavior.
1132:   // CONNECT "urls" are actually host:port so look like absolute URLs to the above checks.
1133:   // Absolute URLS in CONNECT requests will be rejected below by the URL class validation.
1134: 
1135:   /**
1136:    * @param scheme the scheme to validate
1137:    * @return bool true if the scheme is http.
1138:    */
1139:   if (!codec_settings_.allow_absolute_url_ && !is_connect) {
1140:     headers.addViaMove(std::move(path), std::move(active_request_->request_url_));
1141:     return okStatus();
1142:   }
1143: 
1144:   Utility::Url absolute_url;
1145:   if (!absolute_url.initialize(active_request_->request_url_.getStringView(), is_connect)) {
1146:     RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().InvalidUrl));
1147:     return codecProtocolError("http/1.1 protocol error: invalid url in request line");
1148:   }
1149:   // RFC7230#5.7
1150:   // When a proxy receives a request with an absolute-form of
1151:   // request-target, the proxy MUST ignore the received Host header field
1152:   // (if any) and instead replace it with the host information of the
1153:   // request-target. A proxy that forwards such a request MUST generate a
1154:   // new Host field-value based on the received request-target rather than
1155:   // forward the received Host field-value.
1156:   headers.setHost(absolute_url.hostAndPort());
1157:   // Add the scheme and validate to ensure no https://
1158:   // requests are accepted over unencrypted connections by front-line Envoys.
1159:   if (!is_connect) {
1160:     headers.setScheme(absl::AsciiStrToLower(absolute_url.scheme()));
1161:     if (!Utility::schemeIsValid(headers.getSchemeValue())) {
1162:       RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().InvalidScheme));
1163:       return codecProtocolError("http/1.1 protocol error: invalid scheme");
1164:     }
1165:     if (codec_settings_.validate_scheme_ && Utility::schemeIsHttps(absolute_url.scheme()) &&
1166:         !connection().ssl()) {
1167:       error_code_ = Http::Code::Forbidden;
1168:       RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().HttpsInPlaintext));
1169:       return codecProtocolError("http/1.1 protocol error: https in the clear");
1170:     }
1171:   }
1172: 
1173:   if (!absolute_url.pathAndQueryParams().empty()) {
1174:     headers.setPath(absolute_url.pathAndQueryParams());
1175:   }
1176:   active_request_->request_url_.clear();
1177:   return okStatus();
1178: }
