1180: Status ServerConnectionImpl::checkProtocolVersion(RequestHeaderMap& headers) {
1181:   if (protocol() == Protocol::Http10) {
1182:     // Assume this is HTTP/1.0. This is fine for HTTP/0.9 but this code will also affect any
1183:     // requests with non-standard version numbers (0.9, 1.3), basically anything which is not
1184:     // HTTP/1.1.
1185:     //
1186:     // The protocol may have shifted in the HTTP/1.0 case so reset it.
1187:     if (!codec_settings_.accept_http_10_) {
1188:       // Send "Upgrade Required" if HTTP/1.0 support is not explicitly configured on.
1189:       error_code_ = Http::Code::UpgradeRequired;
1190:       RETURN_IF_ERROR(sendProtocolError(StreamInfo::ResponseCodeDetails::get().LowVersion));
1191:       return codecProtocolError("Upgrade required for HTTP/1.0 or HTTP/0.9");
1192:     }
1193:     if (!headers.Host() && !codec_settings_.default_host_for_http_10_.empty()) {
1194:       // Add a default host if configured to do so.
1195:       headers.setHost(codec_settings_.default_host_for_http_10_);
1196:     }
1197:   }
1198:   return okStatus();
1199: }
