1201: Envoy::StatusOr<CallbackResult> ServerConnectionImpl::onHeadersCompleteBase() {
1202:   // Handle the case where response happens prior to request complete. It's up to upper layer code
1203:   // to disconnect the connection but we shouldn't fire any more events since it doesn't make
1204:   // sense.
1205:   if (active_request_) {
1206:     auto& headers = absl::get<RequestHeaderMapPtr>(headers_or_trailers_);
1207:     ENVOY_CONN_LOG(trace, "Server: onHeadersComplete size={}", connection_, headers->size());
1208: 
1209:     if (!handling_upgrade_ && headers->Connection()) {
1210:       // If we fail to sanitize the request, return a 400 to the client
1211:       if (!Utility::sanitizeConnectionHeader(*headers)) {
1212:         absl::string_view header_value = headers->getConnectionValue();
1213:         ENVOY_CONN_LOG(debug, "Invalid nominated headers in Connection: {}", connection_,
1214:                        header_value);
1215:         error_code_ = Http::Code::BadRequest;
1216:         RETURN_IF_ERROR(
1217:             sendProtocolError(Http1ResponseCodeDetails::get().ConnectionHeaderSanitization));
1218:         return codecProtocolError("Invalid nominated headers in Connection.");
1219:       }
1220:     }
1221: 
1222:     // Inform the response encoder about any HEAD method, so it can set content
1223:     // length and transfer encoding headers correctly.
1224:     const Http::HeaderValues& header_values = Http::Headers::get();
1225:     active_request_->response_encoder_.setIsResponseToHeadRequest(parser_->methodName() ==
1226:                                                                   header_values.MethodValues.Head);
1227:     active_request_->response_encoder_.setIsResponseToConnectRequest(
1228:         parser_->methodName() == header_values.MethodValues.Connect);
1229: 
1230:     RETURN_IF_ERROR(handlePath(*headers, parser_->methodName()));
1231:     ASSERT(active_request_->request_url_.empty());
1232: 
1233:     headers->setMethod(parser_->methodName());
1234:     RETURN_IF_ERROR(checkProtocolVersion(*headers));
1235: 
1236:     // Make sure the host is valid.
1237:     auto details = HeaderUtility::requestHeadersValid(*headers);
1238:     if (details.has_value()) {
1239:       RETURN_IF_ERROR(sendProtocolError(details.value().get()));
1240:       return codecProtocolError(
1241:           "http/1.1 protocol error: request headers failed spec compliance checks");
1242:     }
1243: 
1244:     // Determine here whether we have a body or not. This uses the new RFC semantics where the
1245:     // presence of content-length or chunked transfer-encoding indicates a body vs. a particular
1246:     // method. If there is no body, we defer raising decodeHeaders() until the parser is flushed
1247:     // with message complete. This allows upper layers to behave like HTTP/2 and prevents a proxy
1248:     // scenario where the higher layers stream through and implicitly switch to chunked transfer
1249:     // encoding because end stream with zero body length has not yet been indicated.
1250:     if (parser_->isChunked() ||
1251:         (parser_->contentLength().has_value() && parser_->contentLength().value() > 0) ||
1252:         handling_upgrade_) {
1253:       active_request_->request_decoder_->decodeHeaders(std::move(headers), false);
1254: 
1255:       // If the connection has been closed (or is closing) after decoding headers, pause the parser
1256:       // so we return control to the caller.
1257:       if (connection_.state() != Network::Connection::State::Open) {
1258:         return parser_->pause();
1259:       }
1260:     } else {
1261:       deferred_end_stream_headers_ = true;
1262:     }
1263:   }
1264: 
1265:   return CallbackResult::Success;
1266: }
