58: // This function is crafted to match the URL validation behavior of the http-parser library.
59: bool isUrlValid(absl::string_view url, bool is_connect) {
60:   if (url.empty()) {
61:     return false;
62:   }
63: 
64:   // Same set of characters are allowed for path and query.
65:   const auto is_valid_path_query_char = [](char c) {
66:     return c == 9 || c == 12 || ('!' <= c && c <= 126);
67:   };
68: 
69:   // The URL may start with a path.
70:   if (auto it = url.begin(); *it == '/' || *it == '*') {
71:     ++it;
72:     return std::all_of(it, url.end(), is_valid_path_query_char);
73:   }
74: 
75:   // If method is not CONNECT, parse scheme.
76:   if (!is_connect) {
77:     // Scheme must start with alpha and be non-empty.
78:     auto it = url.begin();
79:     if (!std::isalpha(*it)) {
80:       return false;
81:     }
82:     ++it;
83:     // Scheme started with an alpha character and the rest of it is alpha, digit, '+', '-' or '.'.
84:     const auto is_scheme_suffix = [](char c) {
85:       return std::isalpha(c) || std::isdigit(c) || c == '+' || c == '-' || c == '.';
86:     };
87:     it = std::find_if_not(it, url.end(), is_scheme_suffix);
88:     url.remove_prefix(it - url.begin());
89:     if (!absl::StartsWith(url, kColonSlashSlash)) {
90:       return false;
91:     }
92:     url.remove_prefix(kColonSlashSlash.length());
93:   }
94: 
95:   // Path and query start with the first '/' or '?' character.
96:   const auto is_path_query_start = [](char c) { return c == '/' || c == '?'; };
97: 
98:   // Divide the rest of the URL into two sections: host, and path/query/fragments.
99:   auto path_query_begin = std::find_if(url.begin(), url.end(), is_path_query_start);
100:   const absl::string_view host = url.substr(0, path_query_begin - url.begin());
101:   const absl::string_view path_query = url.substr(path_query_begin - url.begin());
102: 
103:   const auto valid_host_char = [](char c) {
104:     return std::isalnum(c) || c == '!' || c == '$' || c == '%' || c == '&' || c == '\'' ||
105:            c == '(' || c == ')' || c == '*' || c == '+' || c == ',' || c == '-' || c == '.' ||
106:            c == ':' || c == ';' || c == '=' || c == '@' || c == '[' || c == ']' || c == '_' ||
107:            c == '~';
108:   };
109: 
110:   // Match http-parser's quirk of allowing any number of '@' characters in host
111:   // as long as they are not consecutive.
112:   return std::all_of(host.begin(), host.end(), valid_host_char) && !absl::StrContains(host, "@@") &&
113:          std::all_of(path_query.begin(), path_query.end(), is_valid_path_query_char);
114: }
