116: // Returns true if `version_input` is a valid HTTP version string as defined at
117: // https://www.rfc-editor.org/rfc/rfc9112.html#section-2.3, or empty (for HTTP/0.9).
118: bool isVersionValid(absl::string_view version_input) {
119:   if (version_input.empty()) {
120:     return true;
121:   }
122: 
123:   if (!absl::StartsWith(version_input, kHttpVersionPrefix)) {
124:     return false;
125:   }
126:   version_input.remove_prefix(kHttpVersionPrefix.size());
127: 
128:   // Version number is in the form of "[0-9].[0-9]".
129:   return version_input.size() == 3 && absl::ascii_isdigit(version_input[0]) &&
130:          version_input[1] == '.' && absl::ascii_isdigit(version_input[2]);
131: }
