363:     error_message_ = "HPE_INVALID_CHUNK_SIZE";
364:     break;
365:   case BalsaFrameEnums::HEADERS_TOO_LONG:
366:     error_message_ = "headers size exceeds limit";
367:     break;
368:   case BalsaFrameEnums::TRAILER_TOO_LONG:
369:     error_message_ = "trailers size exceeds limit";
370:     break;
371:   case BalsaFrameEnums::TRAILER_MISSING_COLON:
372:     error_message_ = "HPE_INVALID_HEADER_TOKEN";
