391: void BalsaParser::validateAndProcessHeadersOrTrailersImpl(const quiche::BalsaHeaders& headers,
392:                                                           bool trailers) {
393:   for (const auto& [key, value] : headers.lines()) {
394:     if (status_ == ParserStatus::Error) {
395:       return;
396:     }
397: 
398:     if (!isHeaderNameValid(key)) {
399:       status_ = ParserStatus::Error;
400:       error_message_ = "HPE_INVALID_HEADER_TOKEN";
401:       return;
402:     }
403: 
404:     if (trailers && !enable_trailers_) {
405:       continue;
406:     }
407: 
408:     status_ = convertResult(connection_->onHeaderField(key.data(), key.length()));
409:     if (status_ == ParserStatus::Error) {
410:       return;
411:     }
412: 
413:     // Remove CR and LF characters to match http-parser behavior.
414:     auto is_cr_or_lf = [](char c) { return c == '\r' || c == '\n'; };
415:     if (std::any_of(value.begin(), value.end(), is_cr_or_lf)) {
416:       std::string value_without_cr_or_lf;
417:       value_without_cr_or_lf.reserve(value.size());
418:       for (char c : value) {
419:         if (!is_cr_or_lf(c)) {
420:           value_without_cr_or_lf.push_back(c);
421:         }
422:       }
423:       status_ = convertResult(connection_->onHeaderValue(value_without_cr_or_lf.data(),
424:                                                          value_without_cr_or_lf.length()));
425:     } else {
426:       // No need to copy if header value does not contain CR or LF.
427:       status_ = convertResult(connection_->onHeaderValue(value.data(), value.length()));
428:     }
429:   }
430: }
