707: Envoy::StatusOr<size_t> ConnectionImpl::dispatchSlice(const char* slice, size_t len) {
708:   ASSERT(codec_status_.ok() && dispatching_);
709:   const size_t nread = parser_->execute(slice, len);
710:   if (!codec_status_.ok()) {
711:     return codec_status_;
712:   }
713: 
714:   const ParserStatus status = parser_->getStatus();
715:   if (status != ParserStatus::Ok && status != ParserStatus::Paused) {
716:     absl::string_view error = Http1ResponseCodeDetails::get().HttpCodecError;
717:     if (parser_->errorMessage() == "headers size exceeds limit" ||
718:         parser_->errorMessage() == "trailers size exceeds limit") {
719:       error_code_ = Http::Code::RequestHeaderFieldsTooLarge;
720:       error = Http1ResponseCodeDetails::get().HeadersTooLarge;
721:     } else if (parser_->errorMessage() == "header value contains invalid chars") {
722:       error = Http1ResponseCodeDetails::get().InvalidCharacters;
723:     }
724: 
725:     RETURN_IF_ERROR(sendProtocolError(error));
726:     // Avoid overwriting the codec_status_ set in the callbacks.
727:     ASSERT(codec_status_.ok());
728:     codec_status_ =
729:         codecProtocolError(absl::StrCat("http/1.1 protocol error: ", parser_->errorMessage()));
